package main

import (
    "fmt"
    "sync"
)

type Bank struct {
    accounts map[string]float64
    mu       sync.RWMutex
}

func NewBank() *Bank {
    return &Bank{
        accounts: make(map[string]float64),
    }
}

func (b *Bank) Deposit(account string, amount float64) {
    b.mu.Lock()
    defer b.mu.Unlock()
    b.accounts[account] += amount
    fmt.Printf("Deposited %.2f to %s. New balance: %.2f\n", amount, account, b.accounts[account])
}

func (b *Bank) Withdraw(account string, amount float64) {
    b.mu.Lock()
    defer b.mu.Unlock()
    if b.accounts[account] >= amount {
        b.accounts[account] -= amount
        fmt.Printf("Withdrew %.2f from %s. New balance: %.2f\n", amount, account, b.accounts[account])
    } else {
        fmt.Printf("Failed to withdraw %.2f from %s. Insufficient funds. Balance: %.2f\n", amount, account, b.accounts[account])
    }
}

func (b *Bank) CheckBalance(account string) float64 {
    b.mu.RLock()
    defer b.mu.RUnlock()
    return b.accounts[account]
}

